
const MOVES = [{"num": 1, "name": "Commencing Form", "chinese": "起势", "pinyin": "Qǐ Shì", "simple": "Stand upright, soften the knees, raise both arms to shoulder height, then lower them calmly.", "transition": "Stillness → arms rise → arms lower.", "body": ["Feet shoulder-width", "shoulders drop", "arms float up and press down", "weight centred."], "memory": "The door into the whole form.", "breath": "Inhale up, exhale down.", "common": "Lifting shoulders or locking knees.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-01.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 2, "name": "Part the Wild Horse’s Mane", "chinese": "左右野马分鬃", "pinyin": "Zuǒ Yòu Yě Mǎ Fēn Zōng", "simple": "Step out and separate the hands as if parting a horse’s mane. Repeat left and right.", "transition": "Gather ball → step → shift → open.", "body": ["Hold a ball", "heel lands first", "one hand rises, one hand settles", "torso upright."], "memory": "Ball, step, open.", "breath": "Inhale gather, exhale open.", "common": "Opening before the weight arrives.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-02.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 3, "name": "White Crane Spreads Its Wings", "chinese": "白鹤亮翅", "pinyin": "Bái Hè Liàng Chì", "simple": "Shift back and open one hand high, one hand low, like a crane spreading its wings.", "transition": "Step in lightly and separate high-low.", "body": ["Upper hand protects temple line", "lower hand settles", "front foot light", "chest relaxed."], "memory": "Horizontal opening becomes vertical high-low.", "breath": "Exhale into the shape.", "common": "Leaning back or making it too big.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-03.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 4, "name": "Brush Knee and Push", "chinese": "左右搂膝拗步", "pinyin": "Zuǒ Yòu Lōu Xī Ào Bù", "simple": "Brush one hand past the knee while the other pushes forward. Repeat sides.", "transition": "Circle hands → step → brush low and push high.", "body": ["Push from centre", "brush past knee", "knee tracks toes", "back heel rooted."], "memory": "Brush low, push high.", "breath": "Inhale circle, exhale push.", "common": "Pushing with shoulder only.", "visuals": [{"label": "View 1", "src": "./assets/wudang/move-04-a.gif"}, {"label": "View 2", "src": "./assets/wudang/move-04-b.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 5, "name": "Play the Lute", "chinese": "手挥琵琶", "pinyin": "Shǒu Huī Pí Pá", "simple": "Shift back into empty stance with both hands raised as if holding a lute.", "transition": "Draw front foot in and settle back.", "body": ["Front foot light", "hands frame instrument", "elbows soft", "spine vertical."], "memory": "A pause-shape after forward push.", "breath": "Let breath settle.", "common": "Too much weight on front foot.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-05.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 6, "name": "Repulse Monkey", "chinese": "左右倒卷肱", "pinyin": "Zuǒ Yòu Dào Juǎn Gōng", "simple": "Step backward while one hand pushes forward and the other withdraws.", "transition": "Draw one hand back → step behind → push.", "body": ["Step back carefully", "front hand pushes", "rear hand withdraws", "eyes forward."], "memory": "First backward travelling section.", "breath": "Inhale draw, exhale push.", "common": "Looking down or stepping too narrow.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-06.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 7, "name": "Grasp the Bird’s Tail — Left", "chinese": "左揽雀尾", "pinyin": "Zuǒ Lǎn Què Wěi", "simple": "Ward off, rollback, press and push on the left side.", "transition": "Turn and gather into the four-energy phrase.", "body": ["Ward off rounded", "rollback from waist", "press connected", "push after sinking."], "memory": "Ward off → rollback → press → push.", "breath": "Natural, exhale on final push.", "common": "Making four disconnected poses.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-07.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 8, "name": "Grasp the Bird’s Tail — Right", "chinese": "右揽雀尾", "pinyin": "Yòu Lǎn Què Wěi", "simple": "Repeat ward off, rollback, press and push on the right side.", "transition": "Turn through centre and repeat right.", "body": ["Waist turns first", "structure rounded", "do not overreach", "weight shifts smooth."], "memory": "Same four energies, other side.", "breath": "Let weight shifts guide breath.", "common": "Losing balance in the turn.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-08.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 9, "name": "Single Whip", "chinese": "单鞭", "pinyin": "Dān Biān", "simple": "Form hook hand on one side and extend the other palm outward.", "transition": "Turn, form hook, step out, open palm.", "body": ["Hook relaxed", "palm extends from centre", "stance wide but soft", "eyes to palm."], "memory": "Hook hand + open palm.", "breath": "Exhale into extension.", "common": "Tensing the hook or locking knee.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-09.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 10, "name": "Wave Hands Like Clouds", "chinese": "云手", "pinyin": "Yún Shǒu", "simple": "Step sideways while hands circle like clouds across the body.", "transition": "Turn inward and side-step with continuous circles.", "body": ["Waist leads hands", "side-close-side", "palms face inward", "shoulders relaxed."], "memory": "Travelling side-step loop.", "breath": "Smooth continuous breath.", "common": "Arms moving without waist.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-10.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 11, "name": "Single Whip", "chinese": "单鞭", "pinyin": "Dān Biān", "simple": "Return to hook hand and extended palm after Cloud Hands.", "transition": "Clouds resolve into hook-and-palm.", "body": ["Finish travel before opening", "hook first", "palm opens as weight settles."], "memory": "Clouds end with Single Whip.", "breath": "Exhale as palm opens.", "common": "Rushing out of Cloud Hands.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-11.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 12, "name": "High Pat on Horse", "chinese": "高探马", "pinyin": "Gāo Tàn Mǎ", "simple": "Step in and raise one hand forward as if patting a horse high on the neck.", "transition": "Draw in and narrow the stance.", "body": ["Back hand draws in", "forward hand rises", "front foot light", "chest relaxed."], "memory": "Big shape narrows and becomes compact.", "breath": "Settle inward.", "common": "Making it too aggressive.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-12.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-chi-24-first-part/", "sourceName": "Wudang Shaolin Dream — Tai Chi 24 First Part"}, {"num": 13, "name": "Right Heel Kick", "chinese": "右蹬脚", "pinyin": "Yòu Dēng Jiǎo", "simple": "Gather, lift knee, separate hands and extend the right heel kick.", "transition": "Gather → lift → separate → heel.", "body": ["Balance first", "heel not toes", "standing knee soft", "hands separate."], "memory": "First clear kick.", "breath": "Exhale as kick extends.", "common": "Kicking too high.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-13.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 14, "name": "Strike Ears with Both Fists", "chinese": "双峰贯耳", "pinyin": "Shuāng Fēng Guàn Ěr", "simple": "Step down and bring both fists forward as if striking toward the ears.", "transition": "Land softly after kick, circle fists forward.", "body": ["Both fists arc together", "elbows rounded", "shoulders relaxed."], "memory": "Kick resolves into double-fist strike.", "breath": "Exhale into fists.", "common": "Dropping heavily.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-14.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 15, "name": "Turn and Left Heel Kick", "chinese": "转身左蹬脚", "pinyin": "Zhuǎn Shēn Zuǒ Dēng Jiǎo", "simple": "Turn, gather, lift and extend the left heel kick.", "transition": "Turn first, then gather and kick.", "body": ["Complete turn", "standing leg soft", "hands separate", "eyes follow kick."], "memory": "Same kick idea after a turn.", "breath": "Inhale turn, exhale kick.", "common": "Kicking before turn completes.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-15.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 16, "name": "Snake Creeps Down and Golden Rooster — Left", "chinese": "左下势独立", "pinyin": "Zuǒ Xià Shì Dú Lì", "simple": "Sink low like Snake Creeps Down, then rise into one-legged Golden Rooster.", "transition": "Step out, sink, then rise into balance.", "body": ["Only sink safely", "spine long", "rise from leg and centre", "hand lifts with knee."], "memory": "Low snake → high rooster.", "breath": "Exhale sink, settle as rise.", "common": "Forcing low stance.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-16.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 17, "name": "Snake Creeps Down and Golden Rooster — Right", "chinese": "右下势独立", "pinyin": "Yòu Xià Shì Dú Lì", "simple": "Repeat the low snake and one-legged rooster on the other side.", "transition": "Shift into right-side version.", "body": ["Control transition", "knee tracks foot", "rise smoothly", "upper body calm."], "memory": "Completes the left/right pair.", "breath": "Steady breath.", "common": "Holding breath.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-17.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 18, "name": "Fair Lady Works at Shuttles", "chinese": "左右穿梭", "pinyin": "Zuǒ Yòu Chuān Suō", "simple": "Step diagonally and coordinate one hand up, one hand forward like working a loom.", "transition": "Step diagonally to corners.", "body": ["Diagonal footwork", "upper hand protects", "forward hand pushes", "waist connects arms."], "memory": "Diagonal corners, shuttle hands.", "breath": "Exhale into each diagonal.", "common": "Losing diagonal direction.", "visuals": [{"label": "View 1", "src": "./assets/wudang/move-18-a.gif"}, {"label": "View 2", "src": "./assets/wudang/move-18-b.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 19, "name": "Needle at Sea Bottom", "chinese": "海底针", "pinyin": "Hǎi Dǐ Zhēn", "simple": "Step in and lower one hand as if reaching for a needle at the sea bottom.", "transition": "Draw in, empty front foot, sink hand downward.", "body": ["Front foot light", "reach down without collapsing", "neck long."], "memory": "Energy drops downward.", "breath": "Exhale down softly.", "common": "Rounding the back.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-19.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 20, "name": "Fan Through the Back", "chinese": "闪通臂", "pinyin": "Shǎn Tōng Bì", "simple": "Rise from Needle and open one hand high, one hand forward.", "transition": "Low Needle → rise into open shape.", "body": ["Rise from legs", "high hand guards", "forward palm expresses", "back broad."], "memory": "Low becomes high open Fan.", "breath": "Inhale rise, exhale open.", "common": "Throwing arms.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-20.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 21, "name": "Turn, Deflect, Parry and Punch", "chinese": "转身搬拦捶", "pinyin": "Zhuǎn Shēn Bān Lán Chuí", "simple": "Turn, deflect, parry and finish with a punch.", "transition": "Turn body and organise hands into punch phrase.", "body": ["Turn first", "deflect/parry distinct", "punch from centre", "elbow not locked."], "memory": "Turn → deflect → parry → punch.", "breath": "Exhale punch.", "common": "Forgetting the setup.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-21.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 22, "name": "Apparent Close Up", "chinese": "如封似闭", "pinyin": "Rú Fēng Sì Bì", "simple": "Withdraw the hands, close, then push forward as if sealing.", "transition": "Open fist, withdraw, close and push.", "body": ["Draw back without leaning", "hands close centre", "push with body weight", "wrists soft."], "memory": "After punch: withdraw, seal, push.", "breath": "Inhale withdraw, exhale push.", "common": "Rushing because end is near.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-22.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 23, "name": "Cross Hands", "chinese": "十字手", "pinyin": "Shí Zì Shǒu", "simple": "Turn to face front and cross both hands in front of the chest.", "transition": "Turn and gather into crossed hands.", "body": ["Feet return neutral", "hands cross softly", "shoulders drop", "centre settles."], "memory": "The form gathers before closing.", "breath": "Natural settling breath.", "common": "Crossing too high.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-23.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}, {"num": 24, "name": "Closing Form", "chinese": "收势", "pinyin": "Shōu Shì", "simple": "Lower the hands and return to quiet standing.", "transition": "Separate and lower arms, return to stillness.", "body": ["Hands lower like pressing water", "knees soft", "mind centred", "posture remains alive."], "memory": "Ends as it began: calm and centred.", "breath": "Exhale as hands lower.", "common": "Finishing mentally too early.", "visuals": [{"label": "Guide", "src": "./assets/wudang/move-24.gif"}], "sourceUrl": "https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/", "sourceName": "Wudang Shaolin Dream — Tai Ji Quan 24 Second Part"}];
const APP_VERSION = "1.5.2";
const STORAGE = {
  current: "taichiflow_current_v1",
  known: "taichiflow_known_v1",
  weak: "taichiflow_weak_v1",
  sessions: "taichiflow_sessions_v1"
};

const state = {
  section: "learn",
  index: Number(localStorage.getItem(STORAGE.current) || 0),
  quizMove: null,
  reveal: false,
  demoView: "back",
  timerRunning: false,
  timerSeconds: 0,
  timerTarget: 0,
  timerPlan: "Free practice",
  timerId: null,
  practiceFocus: ""
};

const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));
const esc = s => String(s ?? "").replace(/[&<>"']/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]));
const safeParse = (k,f) => { try { const r = localStorage.getItem(k); return r ? JSON.parse(r) : f; } catch { return f; } };
const saveJSON = (k,v) => localStorage.setItem(k, JSON.stringify(v));
const moveId = m => String(m.num);
const knownSet = () => new Set(safeParse(STORAGE.known, []));
const weakSet = () => new Set(safeParse(STORAGE.weak, []));
const setKnown = s => saveJSON(STORAGE.known, [...s]);
const setWeak = s => saveJSON(STORAGE.weak, [...s]);
const clampIndex = i => Math.max(0, Math.min(MOVES.length - 1, i));
const currentMove = () => MOVES[state.index] || MOVES[0];
const progressPct = () => Math.round((knownSet().size / MOVES.length) * 100);

function go(i){
  state.index = clampIndex(i);
  localStorage.setItem(STORAGE.current, String(state.index));
  render();
}
function goLearn(i){
  state.section = "learn";
  go(i);
}
function toggleKnown(m){
  const s = knownSet();
  s.has(moveId(m)) ? s.delete(moveId(m)) : s.add(moveId(m));
  setKnown(s);
  render();
}
function toggleWeak(m){
  const s = weakSet();
  s.has(moveId(m)) ? s.delete(moveId(m)) : s.add(moveId(m));
  setWeak(s);
  render();
}
function randomMove(pool=MOVES){
  return pool[Math.floor(Math.random() * pool.length)] || MOVES[0];
}
function newQuiz(){
  const weakMoves = [...weakSet()].map(id => MOVES.find(m => moveId(m) === id)).filter(m => m && m.num < 24);
  const pool = weakMoves.length ? [...weakMoves, ...MOVES.slice(0, -1)] : MOVES.slice(0, -1);
  state.quizMove = randomMove(pool);
  state.reveal = false;
  render();
}
function formatTime(s){
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${String(m).padStart(2,"0")}:${String(r).padStart(2,"0")}`;
}
function displayTimer(){
  const shown = state.timerTarget > 0 ? Math.max(0, state.timerTarget - state.timerSeconds) : state.timerSeconds;
  return formatTime(shown);
}
function startTimer(plan="Free practice", target=0, focus=""){
  state.timerPlan = plan;
  state.timerTarget = target;
  state.practiceFocus = focus;
  if(!state.timerRunning){
    state.timerRunning = true;
    state.timerId = setInterval(() => {
      state.timerSeconds++;
      const el = $("#timerTime");
      if(el) el.textContent = displayTimer();
      if(state.timerTarget > 0 && state.timerSeconds >= state.timerTarget){
        pauseTimer(false);
        const msg = $("#timerMessage");
        if(msg){ msg.hidden = false; msg.textContent = `${state.timerPlan} complete. Save it, or repeat once more slowly.`; }
      }
    }, 1000);
  }
  render();
}
function pauseTimer(doRender=true){
  state.timerRunning = false;
  clearInterval(state.timerId);
  state.timerId = null;
  if(doRender) render();
}
function resetTimer(){
  pauseTimer(false);
  state.timerSeconds = 0;
  state.timerTarget = 0;
  state.timerPlan = "Free practice";
  state.practiceFocus = "";
  render();
}
function saveSession(){
  const sessions = safeParse(STORAGE.sessions, []);
  sessions.unshift({ at: new Date().toISOString(), seconds: state.timerSeconds, known: knownSet().size, plan: state.timerPlan });
  saveJSON(STORAGE.sessions, sessions.slice(0, 20));
  resetTimer();
}
function startPlan(plan){
  state.section = "practice";
  state.timerSeconds = 0;
  if(plan === "sequence") startTimer("3-minute sequence recall", 180, "Say the 24 names in order. No GIFs, no movement. If you hesitate, mark that move weak afterwards.");
  if(plan === "slow") startTimer("10-minute slow form", 600, "Move through the full form slowly. If you forget, check only the current move, then continue.");
  if(plan === "weak"){
    const weak = [...weakSet()].map(id => MOVES.find(m => moveId(m) === id)).filter(Boolean);
    if(weak.length) state.index = MOVES.indexOf(weak[0]);
    startTimer("5-minute weak-point loop", 300, weak.length ? "Drill each weak move as: previous → current → next. Keep it small and accurate." : "No weak moves marked yet. Mark shaky moves first, or use this time to find them.");
  }
}

function visualFigure(v,m,mode=""){
  return `<figure class="visual-figure ${mode}"><img src="${esc(v.src)}" alt="${esc(m.name)} visual guide" loading="lazy"><figcaption>${esc(v.label)}</figcaption></figure>`;
}
function visualBlock(m){
  const prevDisabled = m.num <= 1 ? "disabled" : "";
  const nextDisabled = m.num >= MOVES.length ? "disabled" : "";
  return `<section class="visual-block">
    <div class="visual-head">
      <div>
        <div class="eyebrow">Real visual guide</div>
        <h3>${m.num}. ${esc(m.name)}</h3>
        <p>Watch the GIF, then do <strong>previous → current → next</strong> without looking.</p>
      </div>
      <button class="pill-btn" data-nav="visuals">All visuals</button>
    </div>
    <div class="visual-grid ${m.visuals.length > 1 ? "multi" : ""}">${m.visuals.map(v => visualFigure(v,m)).join("")}</div>
    <div class="visual-nav">
      <button class="nav-big" data-action="prev" ${prevDisabled}>← Previous move</button>
      <button class="nav-big" data-action="next" ${nextDisabled}>Next move →</button>
    </div>
  </section>`;
}
function moveCard(m, mode="full"){
  const known = knownSet().has(moveId(m));
  const weak = weakSet().has(moveId(m));
  const prev = MOVES[m.num - 2];
  const next = MOVES[m.num];
  return `<article class="move-card ${mode}">
    <div class="move-top">
      <div>
        <div class="eyebrow">Move ${m.num} of 24 · ${esc(m.chinese)} · ${esc(m.pinyin)}</div>
        <h2>${esc(m.name)}</h2>
        <p class="simple">${esc(m.simple)}</p>
      </div>
      <div class="move-actions">
        <button class="pill-btn ${known ? "active" : ""}" data-action="known" data-num="${m.num}">${known ? "Known ✓" : "Mark known"}</button>
        <button class="pill-btn ${weak ? "warn" : ""}" data-action="weak" data-num="${m.num}">${weak ? "Weak ★" : "Mark weak"}</button>
      </div>
    </div>
    ${mode === "compact" ? `<div class="compact-visual">${visualFigure(m.visuals[0],m,"thumb")}</div>` : `
      ${visualBlock(m)}
      <section class="flow-strip">
        <button data-action="go" data-index="${m.num - 2}" ${!prev ? "disabled" : ""}><span>Previous</span><strong>${prev ? esc(prev.name) : "Start"}</strong></button>
        <div><span>Current</span><strong>${esc(m.name)}</strong></div>
        <button data-action="go" data-index="${m.num}" ${!next ? "disabled" : ""}><span>Next</span><strong>${next ? esc(next.name) : "Finish"}</strong></button>
      </section>
      <section class="cue-grid">
        <div class="cue-card"><div class="eyebrow">Transition cue</div><p>${esc(m.transition)}</p></div>
        <div class="cue-card"><div class="eyebrow">Breath</div><p>${esc(m.breath)}</p></div>
        <div class="cue-card"><div class="eyebrow">Memory hook</div><p>${esc(m.memory)}</p></div>
        <div class="cue-card"><div class="eyebrow">Common mistake</div><p>${esc(m.common)}</p></div>
      </section>
      <section class="body-list"><div class="eyebrow">Body cues</div><ul>${m.body.map(x => `<li>${esc(x)}</li>`).join("")}</ul></section>
    `}
  </article>`;
}

function renderLearn(){
  const m = currentMove();
  $("#app").innerHTML = `<section class="hero">
    <div><div class="eyebrow">TaichiFlow v${APP_VERSION} · Yang 24 Form</div><h1>Learn one move at a time.</h1><p>Watch the real GIF, read the transition cue, then practise previous → current → next. That is the memory loop.</p></div>
    <div class="hero-stat"><strong>${progressPct()}%</strong><span>known</span></div>
  </section>
  <section class="how-card">
    <strong>How to use this page:</strong>
    <span>1. Watch the GIF.</span><span>2. Say the move name aloud.</span><span>3. Do previous → current → next without looking.</span><span>4. Mark weak if you hesitate.</span>
  </section>
  <section class="stepper">
    <button class="nav-big" data-action="prev" ${state.index === 0 ? "disabled" : ""}>← Previous</button>
    <input id="moveRange" type="range" min="0" max="${MOVES.length-1}" value="${state.index}">
    <button class="nav-big" data-action="next" ${state.index === MOVES.length-1 ? "disabled" : ""}>Next →</button>
  </section>
  ${moveCard(m)}
  <section class="sequence-bar">${MOVES.map((x,i) => `<button class="dot ${i===state.index ? "active" : ""} ${knownSet().has(moveId(x)) ? "known" : ""}" data-action="go" data-index="${i}" title="${esc(x.name)}">${x.num}</button>`).join("")}</section>`;
}
function renderSequence(){
  $("#app").innerHTML = `<section class="page-head"><div><h1>Full sequence</h1><p>Use this as the map. Tap a move to study it.</p></div></section>
  <section class="sequence-list">${MOVES.map((m,i) => `<button class="sequence-row" data-action="go-learn" data-index="${i}"><span>${m.num}</span><img src="${esc(m.visuals[0].src)}" alt="" loading="lazy"><div><strong>${esc(m.name)}</strong><em>${esc(m.chinese)} · ${esc(m.pinyin)}</em></div><small>${knownSet().has(moveId(m)) ? "Known" : "Study"}</small></button>`).join("")}</section>`;
}
function renderVisuals(){
  const part1 = MOVES.filter(m => m.num <= 12);
  const part2 = MOVES.filter(m => m.num > 12);
  const group = (title, items, url) => `<section class="visuals-section"><div class="visuals-section-head"><div><div class="eyebrow">${title}</div><h2>${items[0].num}–${items[items.length-1].num}</h2></div><a class="pill-btn" href="${url}" target="_blank" rel="noopener noreferrer">Original tutorial</a></div><div class="visuals-grid">${items.map(m => `<article class="visual-card"><button data-action="go-learn" data-index="${m.num-1}"><strong>${m.num}. ${esc(m.name)}</strong><span>${esc(m.pinyin)}</span></button><div class="visual-card-media">${m.visuals.map(v => visualFigure(v,m)).join("")}</div></article>`).join("")}</div></section>`;
  $("#app").innerHTML = `<section class="page-head"><div><h1>Visual guide</h1><p>All real GIFs in one place. Use this when you want to browse the movement shapes quickly.</p></div></section>${group("Part one",part1,"https://wudangshaolindream.com/en/tai-chi-24-first-part/")}${group("Part two",part2,"https://wudangshaolindream.com/en/tai-ji-quan-24-second-part/")}`;
}
function renderDrill(){
  if(!state.quizMove) state.quizMove = MOVES[0];
  const m = state.quizMove;
  const answer = MOVES[m.num] || null;
  let unique = [answer, randomMove(), randomMove(), randomMove()].filter(Boolean);
  const seen = new Set();
  unique = unique.filter(o => { if(seen.has(o.num)) return false; seen.add(o.num); return true; });
  while(unique.length < 4){ const r = randomMove(); if(!seen.has(r.num)){ seen.add(r.num); unique.push(r); } }
  unique.sort(() => Math.random() - .5);
  const prev = MOVES[m.num - 2];
  $("#app").innerHTML = `<section class="page-head"><div><h1>Memory drill</h1><p>This trains sequence recall. The goal is not trivia; it is remembering what your body should do next.</p></div><button class="pill-btn" data-action="newQuiz">New question</button></section>
  <section class="drill-how"><strong>How to use it:</strong><span>1. Look at the current move.</span><span>2. Say the next move before touching the answers.</span><span>3. Choose the answer.</span><span>4. Physically do ${prev ? "previous → " : ""}current → next.</span></section>
  <section class="drill-card"><div class="eyebrow">Current move</div><h2>${m.num}. ${esc(m.name)}</h2><p>${esc(m.chinese)} · ${esc(m.pinyin)}</p><div class="quiz-visual">${visualFigure(m.visuals[0],m,"thumb")}</div><div class="eyebrow">What comes next?</div><div class="quiz-options">${unique.map(o => `<button class="quiz-btn" data-action="answer" data-correct="${answer && o.num === answer.num ? "yes" : "no"}" data-next="${answer ? answer.num : ""}">${o.num}. ${esc(o.name)}</button>`).join("")}</div><div id="quizResult" class="quiz-result" hidden></div><div id="quizActions" class="post-answer-actions" hidden></div><button class="secondary-link" data-action="reveal">${state.reveal ? "Hide answer" : "Reveal answer"}</button>${state.reveal && answer ? `<div class="answer-box">Answer: <strong>${answer.num}. ${esc(answer.name)}</strong><p>${esc(answer.transition)}</p></div>` : ""}</section>`;
}
function renderPractice(){
  const sessions = safeParse(STORAGE.sessions, []);
  $("#app").innerHTML = `<section class="page-head"><div><h1>Practice</h1><p>Choose a mode. The timer is only there to create a simple routine, not pressure.</p></div></section>
  <section class="practice-plan-grid">
    <button class="plan-card" data-action="plan-sequence"><strong>3-minute sequence recall</strong><span>Say moves 1–24 in order. No movement, no GIFs. Use this to build the mental map.</span></button>
    <button class="plan-card" data-action="plan-slow"><strong>10-minute slow form</strong><span>Do the full form slowly. If you forget, check only the current move and continue.</span></button>
    <button class="plan-card" data-action="plan-weak"><strong>5-minute weak-point loop</strong><span>Drill shaky moves as previous → current → next. This is the fastest way to fix gaps.</span></button>
  </section>
  <section class="timer-card"><div class="eyebrow">${esc(state.timerPlan)}</div><div id="timerTime" class="timer-time">${displayTimer()}</div><p class="timer-focus">${esc(state.practiceFocus || "Choose a plan above, or start a free timer.")}</p><div id="timerMessage" class="quiz-result correct" hidden></div><div class="timer-actions">${state.timerRunning ? `<button class="pill-btn active" data-action="pauseTimer">Pause</button>` : `<button class="pill-btn active" data-action="startTimer">Start free timer</button>`}<button class="pill-btn" data-action="resetTimer">Reset</button><button class="pill-btn" data-action="saveSession">Save session</button></div></section>
  <section class="sessions"><h2>Recent sessions</h2>${sessions.length ? sessions.map(s => `<div><strong>${formatTime(s.seconds)}</strong><span>${new Date(s.at).toLocaleString()} · ${esc(s.plan || "Practice")} · ${s.known} known</span></div>`).join("") : `<p>No saved sessions yet.</p>`}</section>`;
}
function renderWeak(){
  const weak = [...weakSet()].map(id => MOVES.find(m => moveId(m) === id)).filter(Boolean);
  $("#app").innerHTML = `<section class="page-head"><div><h1>Weak points</h1><p>These are the moves you marked as shaky. Drill the transition around them, not only the pose.</p></div><button class="pill-btn" data-action="plan-weak">Start weak loop</button></section><section class="grid">${weak.length ? weak.map(m => moveCard(m,"compact")).join("") : `<div class="empty-card">No weak points marked yet. When a move feels slippery, mark it weak.</div>`}</section>`;
}

