function renderAbout(){
  $("#app").innerHTML = `<section class="about-card"><h1>About TaichiFlow</h1><p>TaichiFlow helps you build a healthy Tai Chi habit by making the Yang 24 sequence easier to remember: real GIFs, simple cues, memory drills and short practice modes.</p><div class="stat-grid"><div><strong>24</strong><span>moves</span></div><div><strong>${knownSet().size}</strong><span>known</span></div><div><strong>${weakSet().size}</strong><span>weak points</span></div></div><div class="notes"><p><strong>Best loop:</strong> watch one GIF, read one transition cue, then practise previous → current → next without looking.</p><p><strong>Safety:</strong> do not force low stances or high kicks. Keep knees tracking over toes.</p><p><strong>Visual source:</strong> GIFs are stored locally from the two Wudang Shaolin Dream tutorial pages provided for this build.</p></div></section>`;
}
function render(){
  $$(".nav-btn").forEach(b => b.classList.toggle("active", b.dataset.nav === state.section));
  if(state.section === "learn") renderLearn();
  if(state.section === "sequence") renderSequence();
  if(state.section === "visuals") renderVisuals();
  if(state.section === "drill") renderDrill();
  if(state.section === "practice") renderPractice();
  if(state.section === "demo") renderDemo();
  if(state.section === "weak") renderWeak();
  if(state.section === "about") renderAbout();
}
function handleClick(e){

  const demoToggle = e.target.closest("[data-demo-view]");
  if(demoToggle){
    state.demoView = demoToggle.dataset.demoView === "front" ? "front" : "back";
    state.section = "demo";
    render();
    return;
  }
  const nav = e.target.closest("[data-nav]");
  if(nav){ state.section = nav.dataset.nav; render(); return; }
  const btn = e.target.closest("[data-action]");
  if(!btn) return;
  const action = btn.dataset.action;
  if(action === "prev") go(state.index - 1);
  if(action === "next") go(state.index + 1);
  if(action === "go") go(Number(btn.dataset.index));
  if(action === "go-learn") goLearn(Number(btn.dataset.index));
  if(action === "known") toggleKnown(MOVES[Number(btn.dataset.num) - 1]);
  if(action === "weak") toggleWeak(MOVES[Number(btn.dataset.num) - 1]);
  if(action === "newQuiz") newQuiz();
  if(action === "reveal"){ state.reveal = !state.reveal; render(); }
  if(action === "answer"){
    const result = $("#quizResult");
    const actions = $("#quizActions");
    const correct = btn.dataset.correct === "yes";
    const answer = MOVES[Number(btn.dataset.next) - 1];
    result.hidden = false;
    result.className = "quiz-result " + (correct ? "correct" : "wrong");
    result.innerHTML = correct ? `Correct. Now physically do <strong>${esc(state.quizMove.name)} → ${esc(answer.name)}</strong>.` : `Not that one. The answer is <strong>${answer ? answer.num + ". " + esc(answer.name) : "Finish"}</strong>. Mark this area weak and drill it slowly.`;
    if(!correct && state.quizMove){ const s = weakSet(); s.add(moveId(state.quizMove)); setWeak(s); }
    actions.hidden = false;
    actions.innerHTML = `${answer ? `<button class="pill-btn" data-action="go-learn" data-index="${answer.num - 1}">Study next move</button>` : ""}<button class="pill-btn" data-action="newQuiz">Another question</button>`;
  }
  if(action === "startTimer") startTimer("Free practice", 0, "Use this as an open practice timer.");
  if(action === "pauseTimer") pauseTimer();
  if(action === "resetTimer") resetTimer();
  if(action === "saveSession") saveSession();
  if(action === "plan-sequence") startPlan("sequence");
  if(action === "plan-slow") startPlan("slow");
  if(action === "plan-weak") startPlan("weak");
}
function handleInput(e){
  if(e.target.id === "moveRange") go(Number(e.target.value));
}
function boot(){
  document.body.innerHTML = `<div class="app-shell"><header class="topbar"><div class="brand"><div class="logo-mark">太</div><div><strong>TaichiFlow</strong><span>Yang 24 sequence trainer</span></div></div><nav class="nav"><button class="nav-btn active" data-nav="learn">Learn</button><button class="nav-btn" data-nav="sequence">Sequence</button><button class="nav-btn" data-nav="visuals">Visuals</button><button class="nav-btn" data-nav="drill">Drill</button><button class="nav-btn" data-nav="practice">Practice</button>
          <button class="nav-btn" data-nav="demo">Full Practice</button><button class="nav-btn" data-nav="weak">Weak points</button><button class="nav-btn" data-nav="about">About</button></nav></header><main id="app"></main></div>`;
  document.addEventListener("click", handleClick);
  document.addEventListener("input", handleInput);
  if("serviceWorker" in navigator) navigator.serviceWorker.register("./service-worker.js").catch(() => {});
  newQuiz();
  state.section = "learn";
  render();
}
document.addEventListener("DOMContentLoaded", boot);
